require "config.Define"

VideoAdHelper = {}
VideoAdHelper.BuildingRecord = {}

function VideoAdHelper:initPlayerData(player)
    local key = DateUtil.getYearDay()
    if player.videoAdRecord.dayKey ~= key then
        player.videoAdRecord = {
            moneyTimes = 0,
            buildingTimes = 0,
            tntTimes = 0,
            ladderTimes = 0,
            dayKey = key
        }
    end
end

function VideoAdHelper:checkShowShopAd(player)
    VideoAdHelper:checkShowTNTAd(player)
    VideoAdHelper:checkShowLadderAd(player)
end

function VideoAdHelper:checkShowMoneyAd(player)
    LuaTimer:schedule(function(userId)
        local c_player = PlayerManager:getPlayerByUserId(userId)
        if not c_player then
            return
        end
        if c_player.videoAdRecord.moneyTimes >= GameConfig.videoAdMoneyTimes then
            return
        end
        if os.time() - c_player.showVideoMoneyAdTime < GameConfig.videoAdMoneyCd then
            return
        end
        local params = {
            title = "tycoon.ad.money.title",
            hint = "tycoon.ad.money.hint",
            icon = "set:tycoon_ad.json image:ic_money",
            count = "+" .. GameConfig.videoAdMoney,
            btnText = "tycoon.ad.money.btn",
            AdType = Define.AdType.Money
        }
        local data = DataBuilder.new():fromTable(params):getData()
        GamePacketSender:sendTycoonVideoData(c_player.rakssid, data)
        c_player.showVideoMoneyAdTime = os.time()
    end, 1000, nil, player.userId)
end

function VideoAdHelper:doGetMoneyAdReward(player)
    if player.videoAdRecord.moneyTimes >= GameConfig.videoAdMoneyTimes then
        return
    end
    player:addCurrency(GameConfig.videoAdMoney)
    player.videoAdRecord.moneyTimes = player.videoAdRecord.moneyTimes + 1
end

function VideoAdHelper:checkShowBuildingAd(player, npc)
    LuaTimer:schedule(function(userId, npc)
        local c_player = PlayerManager:getPlayerByUserId(userId)
        if not c_player then
            return
        end
        if c_player.videoAdRecord.buildingTimes >= GameConfig.videoAdBuildingTimes then
            return
        end
        if os.time() - c_player.showVideoBuildingAdTime < GameConfig.videoAdBuildingCd then
            return
        end
        local money = c_player:getCurrency()
        local price = npc:getPrice()
        if price - money > GameConfig.videoAdBuilding then
            return
        end
        local params = {
            title = "tycoon.ad.build.title",
            hint = "tycoon.ad.build.hint",
            icon = "set:tycoon_ad.json image:ic_building",
            count = "",
            btnText = "tycoon.ad.build.btn",
            AdType = Define.AdType.Building
        }
        local data = DataBuilder.new():fromTable(params):getData()
        GamePacketSender:sendTycoonVideoData(c_player.rakssid, data)
        VideoAdHelper.BuildingRecord[tostring(c_player.userId)] = npc.entityId
        c_player.showVideoBuildingAdTime = os.time()
    end, 1000, nil, player.userId, npc)
end

function VideoAdHelper:doGetBuildingAdReward(player)
    if player.videoAdRecord.buildingTimes >= GameConfig.videoAdBuildingTimes then
        return
    end
    local entityId = self.BuildingRecord[tostring(player.userId)] or 0
    local npc = GameManager:getNpcByEntityId(entityId)
    if not npc then
        return
    end
    local price = math.max(npc:getPrice() - GameConfig.videoAdBuilding, 0)
    npc:onBuild(player, price)
    player.videoAdRecord.buildingTimes = player.videoAdRecord.buildingTimes + 1
end

function VideoAdHelper:checkShowTNTAd(player)
    local params = {
        itemId = BlockID.TNT,
        adType = Define.AdType.AppShop,
        isShow = false
    }
    if player.getTntAdReward or player.videoAdRecord.tntTimes >= GameConfig.videoAdTntTimes then
        local data = DataBuilder.new():fromTable(params):getData()
        GamePacketSender:sendAppShopVideoData(player.rakssid, data)
    else
        params.isShow = true
        local data = DataBuilder.new():fromTable(params):getData()
        GamePacketSender:sendAppShopVideoData(player.rakssid, data)
    end
end

function VideoAdHelper:doGetTNTAdReward(player)
    if player.getTntAdReward or player.videoAdRecord.tntTimes >= GameConfig.videoAdTntTimes then
        return
    end
    player:addItem(BlockID.TNT, 1, 0)
    player.getTntAdReward = true
    player.videoAdRecord.tntTimes = player.videoAdRecord.tntTimes + 1
    HostApi.notifyGetItem(player.rakssid, BlockID.TNT, 0, 1)
    VideoAdHelper:checkShowTNTAd(player)
end

function VideoAdHelper:checkShowLadderAd(player)
    local params = {
        itemId = BlockID.LADDER,
        adType = Define.AdType.AppShop,
        isShow = false
    }
    if player.getLadderAdReward or player.videoAdRecord.ladderTimes >= GameConfig.videoAdLadderTimes then
        local data = DataBuilder.new():fromTable(params):getData()
        GamePacketSender:sendAppShopVideoData(player.rakssid, data)
    else
        params.isShow = true
        local data = DataBuilder.new():fromTable(params):getData()
        GamePacketSender:sendAppShopVideoData(player.rakssid, data)
    end
end

function VideoAdHelper:doGetLadderAdReward(player)
    if player.getLadderAdReward or player.videoAdRecord.ladderTimes >= GameConfig.videoAdLadderTimes then
        return
    end
    player:addItem(BlockID.LADDER, 5, 0)
    player.getLadderAdReward = true
    player.videoAdRecord.ladderTimes = player.videoAdRecord.ladderTimes + 1
    HostApi.notifyGetItem(player.rakssid, BlockID.LADDER, 0, 5)
    VideoAdHelper:checkShowLadderAd(player)
end

return VideoAdHelper